<?php
namespace App\Domain\Accounting\Services;
use App\Enums\JournalStatus;use App\Models\JournalEntryLine;use App\Models\LedgerAccount;use Illuminate\Support\Facades\DB;
class FinancialReports{public function trialBalance(string $from,string $to):array{$rows=$this->balances($from,$to);$debits=collect($rows)->sum('debit_minor');$credits=collect($rows)->sum('credit_minor');return ['from'=>$from,'to'=>$to,'accounts'=>$rows,'total_debit_minor'=>$debits,'total_credit_minor'=>$credits,'balanced'=>$debits===$credits];}public function incomeStatement(string $from,string $to):array{$rows=collect($this->balances($from,$to));$income=$rows->where('type','income')->values();$expenses=$rows->where('type','expense')->values();$totalIncome=$income->sum(fn($r)=>$r['credit_minor']-$r['debit_minor']);$totalExpenses=$expenses->sum(fn($r)=>$r['debit_minor']-$r['credit_minor']);return ['from'=>$from,'to'=>$to,'income'=>$income,'expenses'=>$expenses,'total_income_minor'=>$totalIncome,'total_expenses_minor'=>$totalExpenses,'net_surplus_minor'=>$totalIncome-$totalExpenses];}public function balanceSheet(string $asOf):array{$rows=collect($this->balances('1900-01-01',$asOf));$assets=$rows->where('type','asset')->values();$liabilities=$rows->where('type','liability')->values();$equity=$rows->where('type','equity')->values();$surplus=$rows->where('type','income')->sum(fn($r)=>$r['credit_minor']-$r['debit_minor'])-$rows->where('type','expense')->sum(fn($r)=>$r['debit_minor']-$r['credit_minor']);return ['as_of'=>$asOf,'assets'=>$assets,'liabilities'=>$liabilities,'equity'=>$equity,'total_assets_minor'=>$assets->sum(fn($r)=>$r['debit_minor']-$r['credit_minor']),'total_liabilities_minor'=>$liabilities->sum(fn($r)=>$r['credit_minor']-$r['debit_minor']),'total_equity_minor'=>$equity->sum(fn($r)=>$r['credit_minor']-$r['debit_minor'])+$surplus,'current_surplus_minor'=>$surplus];}public function subsidiaryLedger(string $dimension,string $id,string $from,string $to):array{$column=match($dimension){'member'=>'member_id','loan'=>'loan_id','branch'=>'branch_id',default=>throw new \InvalidArgumentException('Unsupported subsidiary dimension.')};$lines=JournalEntryLine::query()->with(['entry','account'])->where($column,$id)->whereHas('entry',fn($q)=>$q->where('status',JournalStatus::Posted->value)->whereBetween('entry_date',[$from,$to]))->get()->sortBy(fn($line)=>$line->entry->entry_date->toDateString().$line->id)->values();return ['dimension'=>$dimension,'dimension_id'=>$id,'from'=>$from,'to'=>$to,'total_debit_minor'=>$lines->sum('debit_minor'),'total_credit_minor'=>$lines->sum('credit_minor'),'lines'=>$lines];}private function balances(string $from,string $to):array{return LedgerAccount::query()->leftJoin('journal_entry_lines','ledger_accounts.id','=','journal_entry_lines.ledger_account_id')->leftJoin('journal_entries',function($join)use($from,$to){$join->on('journal_entries.id','=','journal_entry_lines.journal_entry_id')->where('journal_entries.status',JournalStatus::Posted->value)->whereBetween('journal_entries.entry_date',[$from,$to]);})->groupBy('ledger_accounts.id','ledger_accounts.code','ledger_accounts.name','ledger_accounts.type','ledger_accounts.normal_balance')->orderBy('ledger_accounts.code')->get(['ledger_accounts.id','ledger_accounts.code','ledger_accounts.name','ledger_accounts.type','ledger_accounts.normal_balance',DB::raw('COALESCE(SUM(CASE WHEN journal_entries.id IS NOT NULL THEN journal_entry_lines.debit_minor ELSE 0 END),0) as debit_minor'),DB::raw('COALESCE(SUM(CASE WHEN journal_entries.id IS NOT NULL THEN journal_entry_lines.credit_minor ELSE 0 END),0) as credit_minor')])->map(fn($row)=>['id'=>$row->id,'code'=>$row->code,'name'=>$row->name,'type'=>$row->type instanceof \BackedEnum?$row->type->value:$row->type,'normal_balance'=>$row->normal_balance,'debit_minor'=>(int)$row->debit_minor,'credit_minor'=>(int)$row->credit_minor,'balance_minor'=>(int)$row->debit_minor-(int)$row->credit_minor])->all();}}
